    "description": "Retrieves the full current state of a variance application, including property info, review status, document checklist, and existing notes.",
    "parameters": {
      "type": "object",
      "properties": {
        "application_id": {
          "type": "string",
          "description": "The unique identifier for the variance application (e.g., 'VAR-2024-ADA-012')."
        }
      },
      "required": [
        "application_id"
      ]
    },
    "example_output": {
      "application_id": "VAR-2024-ADA-012",
      "review_status": "Pending",
      "document_checklist": {
        "site_plan": true,
        "hardship_statement": true,
        "medical_necessity_doc": false
      },
      "zoning_violations_found": [
        "Section 4.2: Front Yard Setback encroachment"
      ]
    }
  },
  "log_legal_assessment": {
    "description": "Records the reviewer's evaluation regarding the nexus between disability and the requested accommodation, and the assessment of fundamental alterations to safety.",
    "parameters": {
      "type": "object",
      "properties": {
        "application_id": {
          "type": "string"
        },
        "nexus_description": {
          "type": "string",
          "description": "Detailed explanation of how the ramp alleviates the specific barriers posed by the disability."
        },
        "safety_impact_analysis": {
          "type": "string",
          "description": "Evaluation of whether the structure impacts municipal safety or constitutes a fundamental alteration."
        },
        "is_compliant_with_fha": {
          "type": "boolean",
          "description": "Whether the application meets Federal Fair Housing Act mandates."
        }
      },
      "required": [
        "application_id",
        "nexus_description",
        "safety_impact_analysis",
        "is_compliant_with_fha"
      ]
    },
    "example_output": null
  },
  "fast_track_administrative_approval": {
    "description": "Utilizes the most efficient administrative path to approve a Reasonable Accommodation request without a public hearing, preventing 'constructive denial' by delay.",
    "parameters": {
      "type": "object",
      "properties": {
        "application_id": {
          "type": "string"
        },
        "justification": {
          "type": "string",
          "description": "Reasoning for bypassing traditional hearing cycles (e.g., 'Mandated RA under FHA')."
        }
      },
      "required": [
        "application_id",
        "justification"
      ]
    },
    "example_output": {
      "new_status": "Approved_Administrative",
      "estimated_completion_days": 1
    }
  },
  "finalize_determination_with_conditions": {
    "description": "Issues the final decision and adds the formal requirement for future code restoration/reversion.",
    "parameters": {
      "type": "object",
      "properties": {
        "application_id": {
          "type": "string"
        },
        "decision": {
          "type": "string",
          "enum": [
            "Approved",
            "Denied"
          ]
        },
        "reversion_clause_included": {
          "type": "boolean",
          "description": "Must be true. Confirms the property must be restored to code once medical necessity ends."
        },
        "final_notes": {
          "type": "string"
        }
      },
      "required": [
        "application_id",
        "decision",
        "reversion_clause_included"
      ]
    },
    "example_output": {
      "status": "Finalized",
      "determination_code": "RA-PERMIT-2024"
    }
  }
}
